export const HEXAGRAMS = [
  {"num":1,"name":"The Creative","pinyin":"Qián","chinese":"乾","upper":"qian","lower":"qian","lines":[1,1,1,1,1,1],"judgment":"The Creative brings about great success and steady progress; it rewards firm, upright persistence.","image":"Heaven moves with tireless power; the noble one makes himself strong and never rests.","lineTexts":["A dragon lies hidden beneath the waters — do not yet act.","The dragon shows itself in the field; it helps to see a great person.","All day the noble one is active, wary even at nightfall — no blame.","The dragon may leap over the depths, or wait — either way, no blame.","A dragon flies in the heavens; it helps to see a great person.","The dragon overreaches to its height and finds cause to repent."],"keywords":["creativity","heaven","initiative","strength","yang"]},
  {"num":2,"name":"The Receptive","pinyin":"Kūn","chinese":"坤","upper":"kun","lower":"kun","lines":[0,0,0,0,0,0],"judgment":"The Receptive yields great success through the steadfastness of a mare; going first brings confusion, following brings guidance and gain.","image":"Earth's condition is generous devotion; the noble one carries the world with an ample nature.","lineTexts":["Treading on hoarfrost warns that solid ice is coming.","Straight, square, and vast — it works well without effort.","Keep your brilliance hidden while serving; complete the work, claim no credit.","Tie up the sack — no praise, but no blame either.","A yellow lower garment brings supreme good fortune.","Dragons battle in the meadow, their blood dark and yellow."],"keywords":["receptivity","earth","yielding","devotion","yin"]},
  {"num":3,"name":"Difficulty at the Beginning","pinyin":"Zhūn","chinese":"屯","upper":"kan","lower":"zhen","lines":[1,0,0,0,1,0],"judgment":"Sprouting brings great success through persistence; do not press ahead — appoint helpers and let order form.","image":"Clouds and thunder gather; the noble one brings order out of the tangle.","lineTexts":["Held back at the start; stay steadfast, seek helpers, and settle the ground.","Struggling and turning back, not robbers but suitors; the maiden waits ten years to wed.","Chasing deer without a guide only leads into the forest — better to give up than go on.","Turning back to seek union; going forward is fortunate, all is favorable.","The bounty is held back; small persistence brings luck, large striving brings misfortune.","Horses turn away; tears of blood flow."],"keywords":["sprouting","obstacle","perseverance","new start","chaos"]},
  {"num":4,"name":"Youthful Folly","pinyin":"Méng","chinese":"蒙","upper":"gen","lower":"kan","lines":[0,1,0,0,0,1],"judgment":"Folly finds success; the young seeker comes to the teacher, not the reverse — one honest question is answered, repeated pestering is not.","image":"A spring wells up at the mountain's foot; the noble one cultivates character through resolute action.","lineTexts":["Discipline the folly; use restraint, then loosen it, lest rigidity bring regret.","Bearing with the foolish brings fortune; taking a wife brings fortune; the son can manage the house.","Do not take this woman who loses herself at the sight of wealth — nothing is gained.","Folly bound in isolation brings humiliation.","Childlike innocence in learning brings good fortune.","Punishing folly should curb wrongdoing, not become mere violence."],"keywords":["inexperience","learning","teaching","cultivation","folly"]},
  {"num":5,"name":"Waiting","pinyin":"Xū","chinese":"需","upper":"kan","lower":"qian","lines":[1,1,1,0,1,0],"judgment":"With sincerity, waiting shines with success; steadfastness brings fortune, and it is worth crossing the great stream.","image":"Clouds rise into the sky; the noble one eats, drinks, and stays cheerful while he waits.","lineTexts":["Waiting in the open meadow; keep to what endures, and there is no blame.","Waiting on the sand; some small talk arises, but the end is fortunate.","Waiting in the mud invites the enemy's approach.","Waiting in blood — climb out of the pit.","Waiting with food and wine; steadfastness brings good fortune.","Falling into the pit, three uninvited guests arrive; honor them and the end is fortunate."],"keywords":["patience","nourishment","waiting","confidence","timing"]},
  {"num":6,"name":"Conflict","pinyin":"Sòng","chinese":"訟","upper":"qian","lower":"kan","lines":[0,1,0,1,1,1],"judgment":"In conflict, hold sincerity yet stay wary; halting midway brings fortune, pressing to the end brings misfortune — seek the great person, do not cross the great stream.","image":"Heaven and water move apart; the noble one weighs the start of any undertaking.","lineTexts":["Do not prolong the affair; some words are exchanged, but the end is fortunate.","Unable to win the dispute, retreat home; a small household of three hundred escapes trouble.","Live on old virtue; danger passes into fortune. Serve the king but claim no finished work.","Unable to win, turn back to fate, change course, find peace, and stay steadfast — fortune.","Dispute settled by the just — supreme good fortune.","Even if granted a leather belt of honor, by day's end it is stripped away three times."],"keywords":["dispute","caution","litigation","restraint","opposition"]},
  {"num":7,"name":"The Army","pinyin":"Shī","chinese":"師","upper":"kun","lower":"kan","lines":[0,1,0,0,0,0],"judgment":"The army needs firmness and a seasoned leader; then good fortune follows and no blame.","image":"Water gathers within the earth; the noble one nourishes the people and gathers a host.","lineTexts":["The army must set out under proper order; without it, even good aims bring misfortune.","In the midst of the host, steadfastness brings fortune; the king confers his favor three times.","If the army carries corpses in the wagon, there is misfortune.","The army retreats and camps; there is no blame in a wise withdrawal.","Game is in the field — it is right to seize it; let the elder lead, not the young, lest corpses fill the wagon.","The great ruler issues commands, founds states, and vests families — but keep petty men from office."],"keywords":["discipline","leadership","army","organization","mass"]},
  {"num":8,"name":"Holding Together","pinyin":"Bǐ","chinese":"比","upper":"kan","lower":"kun","lines":[0,0,0,0,1,0],"judgment":"Union brings good fortune; inquire again by oracle whether your constancy is sound — then latecomers meet misfortune while the steadfast prosper.","image":"Water lies upon the earth; the ancient kings established states and drew the lords close.","lineTexts":["Join others in sincerity, no blame; let the heart be full as a brimming jar, and fortune comes.","Union that rises from within — steadfastness brings good fortune.","Uniting with the wrong people brings harm.","Uniting openly with the worthy above — steadfastness brings fortune.","The king shows an open union: he drives game from three sides only, sparing what flees; the people feel no dread.","Union without a leading head — misfortune."],"keywords":["union","alliance","solidarity","belonging","attraction"]},
  {"num":9,"name":"The Taming Power of the Small","pinyin":"Xiǎo Chù","chinese":"小畜","upper":"xun","lower":"qian","lines":[1,1,1,0,1,1],"judgment":"The small restrains; there is success, but dense clouds bring no rain yet — the influence comes from one's own western fields.","image":"Wind drives across the sky; the noble one refines the outward graces of his character.","lineTexts":["Return to your own path — how could there be blame? This is fortunate.","Drawn back to the way by others — good fortune.","The wagon loses its wheel-spokes; man and wife avert their eyes.","With sincerity, blood departs and fear withdraws — no blame.","Sincere and bound to others in trust, sharing wealth with a neighbor.","Rain has come and things rest; the woman who presses too far meets danger — the noble one on the move finds misfortune."],"keywords":["restraint","small taming","gradual","patience","gentle influence"]},
  {"num":10,"name":"Treading","pinyin":"Lǚ","chinese":"履","upper":"qian","lower":"dui","lines":[1,1,0,1,1,1],"judgment":"Treading on the tiger's tail — it does not bite; there is success.","image":"Heaven above, lake below; the noble one distinguishes high from low and steadies the people's aims.","lineTexts":["Walk your plain, simple path and go forward without blame.","Tread a smooth, level road; the steadfast recluse holds firm and finds fortune.","A one-eyed man thinks he sees, a lame man thinks he walks — treading on the tiger, he is bitten; a warrior serves a great prince.","Treading on the tiger's tail, but wary and cautious, the end is fortunate.","Resolute treading; hold firm even in danger.","Look back over the path you have trodden; if all is complete, supreme good fortune follows."],"keywords":["conduct","caution","propriety","courage","careful steps"]},
  {"num":11,"name":"Peace","pinyin":"Tài","chinese":"泰","upper":"kun","lower":"qian","lines":[1,1,1,0,0,0],"judgment":"Peace: the small departs, the great arrives — good fortune and success.","image":"Heaven and earth mingle; the ruler shapes their course and aids the people.","lineTexts":["Pull up the reed and its roots come with it; setting out together brings fortune.","Embrace the uncultured, ford the river on foot, neglect none afar, drop factions — walk the middle way.","No plain without a slope, no going without return; stay steadfast in hardship, keep faith, and enjoy your blessings.","Fluttering down, not on riches but in sincere trust with the neighbors.","King Yi gives his daughter in marriage — a source of blessing and supreme good fortune.","The city wall crumbles back into the moat; give no orders now, and steadfastness turns to regret."],"keywords":["harmony","prosperity","flourishing","balance","communion"]},
  {"num":12,"name":"Standstill","pinyin":"Pǐ","chinese":"否","upper":"qian","lower":"kun","lines":[0,0,0,1,1,1],"judgment":"Standstill is the work of unworthy men; it does not favor the noble one's constancy — the great departs, the small arrives.","image":"Heaven and earth draw apart; the noble one withdraws his worth to escape hardship and refuses the lure of honors.","lineTexts":["Pull up the reed with its roots; steadfastness brings fortune and success.","They bear and endure; for the small this is fortune, for the great this standstill leads through to success.","They carry shame concealed within.","Acting on the command from above, no blame; companions share the blessing.","The standstill wanes; the great person finds fortune, though he warns himself it may fail, and binds it fast.","The standstill overturns — first obstruction, then rejoicing."],"keywords":["stagnation","obstruction","withdrawal","decline","separation"]},
  {"num":13,"name":"Fellowship with Others","pinyin":"Tóng Rén","chinese":"同人","upper":"qian","lower":"li","lines":[1,0,1,1,1,1],"judgment":"Fellowship in the open field brings success; it is worth crossing the great stream, and the noble one's constancy prevails.","image":"Heaven above, fire below reaching up to it; the noble one sorts the clans and distinguishes things.","lineTexts":["Fellowship at the gate, openly — no blame.","Fellowship confined to one's own clan — cause for regret.","Weapons hidden in the thicket, watching from the high ground — no attack comes for three years.","He climbs the wall to attack but cannot; in the end this restraint is fortunate.","Fellowship first weeps and laments, then laughs — after great struggle the two meet.","Fellowship in the meadow beyond the walls — no regret."],"keywords":["fellowship","community","openness","cooperation","harmony"]},
  {"num":14,"name":"Possession in Great Measure","pinyin":"Dà Yǒu","chinese":"大有","upper":"li","lower":"qian","lines":[1,1,1,1,0,1],"judgment":"Great possession brings supreme success.","image":"Fire high above heaven; the noble one curbs evil, favors good, and yields to heaven's benign will.","lineTexts":["No dealings yet with what harms; know the hardship ahead, and there is no blame.","A great wagon for loading; wherever you go, no blame.","A prince offers tribute to the Son of Heaven; a petty man could not do this.","Keep your abundance in check, not flaunting it — no blame.","Sincerity that meets others openly and with dignity — good fortune.","Heaven itself blesses him; good fortune, nothing but favor."],"keywords":["abundance","possession","clarity","greatness","generosity"]},
  {"num":15,"name":"Modesty","pinyin":"Qiān","chinese":"謙","upper":"kun","lower":"gen","lines":[0,0,1,0,0,0],"judgment":"Modesty brings success; the noble one carries things through to the end.","image":"A mountain hidden within the earth; the noble one reduces what is too much and adds to what is too little, weighing things to make them even.","lineTexts":["Modest upon modest — the noble one may cross the great stream with good fortune.","Modesty that speaks out; steadfastness brings fortune.","Toiling yet modest — the noble one carries it through with good fortune.","Everything favors one who displays his modesty.","Not wealthy, yet drawing neighbors along; it is right to advance, even with force, and all is favorable.","Modesty that speaks out; it is right to set armies moving and correct one's own domain."],"keywords":["humility","modesty","balance","restraint","moderation"]},
  {"num":16,"name":"Enthusiasm","pinyin":"Yù","chinese":"豫","upper":"zhen","lower":"kun","lines":[0,0,0,1,0,0],"judgment":"Enthusiasm: it is well to install helpers and set the armies marching.","image":"Thunder bursts from the earth resounding; the ancient kings made music to honor virtue and offered it to the Divine and their ancestors.","lineTexts":["Enthusiasm loudly proclaimed brings misfortune.","Firm as a rock, not waiting the day out; steadfastness brings good fortune.","Enthusiasm that gazes upward for favor brings regret; delay only deepens it.","The source of enthusiasm; great things are gained — do not doubt, and friends gather round.","Chronically ailing yet never dying — a lingering, stalled condition.","Enthusiasm gone blind; but if what is begun can still be changed, there is no blame."],"keywords":["enthusiasm","harmony","movement","inspiration","readiness"]},
  {"num":17,"name":"Following","pinyin":"Suí","chinese":"隨","upper":"dui","lower":"zhen","lines":[1,0,0,1,1,0],"judgment":"Following brings supreme success; steadfastness is rewarded, and there is no blame.","image":"Thunder lies within the lake at rest; the noble one goes indoors to rest as evening falls.","lineTexts":["The office changes hands; steadfastness brings fortune, and going out to mingle brings results.","Cling to the little boy and you lose the strong man.","Cling to the strong man and you lose the little boy; following gains what it seeks, but stay steadfast.","Following that seizes a catch — steadfastness would bring misfortune; walk in sincerity and clarity, and how is there blame?","Sincere toward what is good and excellent — good fortune.","He is bound fast and held; the king offers him on the western mountain."],"keywords":["following","adaptation","allegiance","flexibility","responsiveness"]},
  {"num":18,"name":"Work on the Decayed","pinyin":"Gǔ","chinese":"蠱","upper":"gen","lower":"xun","lines":[0,1,1,0,0,1],"judgment":"Repairing what has spoiled brings supreme success; it is worth crossing the great stream — heed the three days before and after the turning point.","image":"Wind at the mountain's foot stirs decay; the noble one rouses the people and nourishes their character.","lineTexts":["Repairing the father's spoiled work; a capable heir shields the father — danger, but the end is fortunate.","Repairing the mother's spoiled work — do not be too rigid here.","Repairing the father's work with some small regret, but no great blame.","Indulging the father's decay — going on this way brings humiliation.","Repairing the father's work in a way that earns praise.","One does not serve king or lord, but sets his own higher aims above them."],"keywords":["repair","renewal","decay","correction","reform"]},
  {"num":19,"name":"Approach","pinyin":"Lín","chinese":"臨","upper":"kun","lower":"dui","lines":[1,1,0,0,0,0],"judgment":"Approach brings supreme success and rewards constancy; but when the eighth month comes there will be misfortune.","image":"Earth rises above the lake; the noble one teaches without limit and shields and sustains the people endlessly.","lineTexts":["Approach in harmony together; steadfastness brings good fortune.","Approach in harmony together; good fortune, and all goes well.","Sweet, easy approach brings nothing worthwhile; grieve over it, and the fault is mended.","Approach drawing near completely — no blame.","Wise approach befitting a great ruler — good fortune.","Generous, honest approach — good fortune, no blame."],"keywords":["approach","growth","advance","oversight","opportunity"]},
  {"num":20,"name":"Contemplation","pinyin":"Guān","chinese":"觀","upper":"xun","lower":"kun","lines":[0,0,0,0,1,1],"judgment":"Contemplation: the hands are washed for the offering but the wine is not yet poured — filled with sincerity and dignity, one looks up in reverence.","image":"Wind moves over the earth; the ancient kings surveyed the regions, observed the people, and set forth their teachings.","lineTexts":["Boyish, shallow looking; harmless for a small man, but shameful for the noble one.","Peering out through the door-crack; fitting for a secluded woman, not for the noble one.","Contemplating one's own life to decide whether to advance or withdraw.","Contemplating the glory of the realm; it is well to be the king's honored guest.","Contemplating one's own life; the noble one keeps himself blameless.","Contemplating the lives of others; the noble one keeps himself blameless."],"keywords":["contemplation","observation","perspective","example","insight"]},
  {"num":21,"name":"Biting Through","pinyin":"Shì Kè","chinese":"噬嗑","upper":"li","lower":"zhen","lines":[1,0,0,1,0,1],"judgment":"Biting through brings success; it is well to administer justice and enforce the law.","image":"Thunder and lightning together; the ancient kings made clear the penalties and enforced the laws.","lineTexts":["Feet locked in the stocks so the toes are hidden — no blame.","Biting through tender flesh until the nose is buried — no blame.","Biting dried meat and hitting something foul; slight regret, but no blame.","Biting dried gristle on the bone, finding metal arrows within; hold firm through hardship, and fortune comes.","Biting dried meat and finding yellow gold; stay steadfast and aware of danger — no blame.","A cangue clamps the neck so the ears are hidden — misfortune."],"keywords":["decisiveness","justice","penalty","resolution","biting through"]},
  {"num":22,"name":"Grace","pinyin":"Bì","chinese":"賁","upper":"gen","lower":"li","lines":[1,0,1,0,0,1],"judgment":"Grace brings success; in small matters it is well to have somewhere to go.","image":"Fire glows at the foot of the mountain; the noble one brings clarity to daily affairs but dares not decide grave cases by mere show.","lineTexts":["Adorning the feet; leave the carriage and go on foot.","Adorning the beard on the chin.","Adorned and glistening; lasting steadfastness brings good fortune.","Adorned or plain as a white horse takes flight — not a robber but a suitor.","Grace in the hills and gardens; the roll of silk is meager, but the shame turns to good fortune.","Plain white grace — simple and unadorned, without blame."],"keywords":["adornment","beauty","form","elegance","refinement"]},
  {"num":23,"name":"Splitting Apart","pinyin":"Bō","chinese":"剝","upper":"gen","lower":"kun","lines":[0,0,0,0,0,1],"judgment":"Splitting apart: it does not favor going anywhere.","image":"The mountain rests upon the earth; those above secure their place by being generous to those below.","lineTexts":["The bed is stripped at the legs; steadfastness is undone, and there is misfortune.","The bed is stripped at the frame; steadfastness is undone, and there is misfortune.","Stripping away, yet without blame in it.","The bed is stripped to the very skin — misfortune.","A string of fish, and palace favor granted through the ladies — everything is favorable.","A great fruit remains uneaten; the noble one gains a carriage, the small man's house is stripped away."],"keywords":["decline","collapse","erosion","dissolution","stripping away"]},
  {"num":24,"name":"Return","pinyin":"Fù","chinese":"復","upper":"kun","lower":"zhen","lines":[1,0,0,0,0,0],"judgment":"Return brings success; going out and coming in without harm, friends arrive without blame — the way turns back and comes home in seven days; it is well to have somewhere to go.","image":"Thunder within the earth; the ancient kings closed the passes at the solstice, so merchants and travelers did not move and the ruler did not tour the regions.","lineTexts":["Returning after only a short straying; no cause for regret — great good fortune.","A quiet, willing return — good fortune.","Returning again and again; danger, but no blame.","Walking amid others, yet returning alone to the right path.","Noble-hearted return, with no regret.","Return that has lost its way — misfortune, calamity; setting armies moving ends in crushing defeat and disaster for the ruler for ten years."],"keywords":["return","renewal","turning point","recovery","rebirth"]},
  {"num":25,"name":"Innocence","pinyin":"Wú Wàng","chinese":"無妄","upper":"qian","lower":"zhen","lines":[1,0,0,1,1,1],"judgment":"Innocence brings supreme success and rewards constancy; but if one is not upright there is trouble, and it does not favor going anywhere.","image":"Thunder rolls beneath heaven, and all things receive their nature; the ancient kings nourished all beings in harmony with the seasons.","lineTexts":["Innocent action — going forward brings good fortune.","Do not count the harvest while plowing, nor the field while breaking it — then it is well to go forward.","Innocence may still meet misfortune: the ox tethered is the traveler's gain and the townsman's loss.","One who can stay steadfast is without blame.","An innocent illness — use no medicine, and it will pass of itself.","Innocent action now brings trouble; nothing is gained by moving."],"keywords":["innocence","spontaneity","naturalness","integrity","the unexpected"]},
  {"num":26,"name":"The Taming Power of the Great","pinyin":"Dà Chù","chinese":"大畜","upper":"gen","lower":"qian","lines":[1,1,1,0,0,1],"judgment":"Great taming rewards constancy; eating away from home brings good fortune, and it is worth crossing the great stream.","image":"Heaven within the mountain; the noble one stores up the sayings and deeds of old to strengthen his character.","lineTexts":["Danger is present; it is well to halt.","The wagon's axle-straps are removed.","A good horse chasing others; hold firm through hardship, practice driving and defense daily, and it is well to go forward.","A headboard on the young bull's horns — great good fortune.","The tusks of a gelded boar — good fortune.","Bearing the ways of heaven itself — success."],"keywords":["restraint","accumulation","great taming","discipline","stored power"]},
  {"num":27,"name":"Nourishment","pinyin":"Yí","chinese":"頤","upper":"gen","lower":"zhen","lines":[1,0,0,0,0,1],"judgment":"Nourishment: constancy brings good fortune; observe what a person nourishes and how they seek to fill their own mouth.","image":"Thunder beneath the mountain; the noble one is careful with his words and temperate in eating and drinking.","lineTexts":["You let your own magic tortoise go and stare at my full jaws with envy — misfortune.","Seeking nourishment against the natural order, turning to the heights for food — going on brings misfortune.","Turning away from true nourishment; steadfastness brings misfortune; do not act on this for ten years.","Turning to the heights for nourishment brings good fortune; watching intently like a tiger, ceaselessly craving — no blame.","Turning against the norm, yet dwelling in steadfastness brings good fortune — but one cannot cross the great stream.","The source of nourishment; aware of the danger, there is good fortune, and it is well to cross the great stream."],"keywords":["nourishment","provision","care","words","sustenance"]},
  {"num":28,"name":"Great Preponderance","pinyin":"Dà Guò","chinese":"大過","upper":"dui","lower":"xun","lines":[0,1,1,1,1,0],"judgment":"Great preponderance: the ridgepole sags; it is well to have somewhere to go, and there is success.","image":"The lake rises over the trees and drowns them; the noble one stands alone unafraid and can withdraw from the world without regret.","lineTexts":["Spreading white rushes beneath the offering — no blame in such care.","A withered poplar sprouts new shoots; an old man takes a young wife — everything is favorable.","The ridgepole bends and buckles — misfortune.","The ridgepole is braced and rises — good fortune; but other motives bring regret.","A withered poplar puts forth blossoms; an old woman takes a young husband — no blame, but no praise.","Fording too deep, the water goes over the head — misfortune, yet no blame in the attempt."],"keywords":["excess","pressure","critical mass","overload","transition"]},
  {"num":29,"name":"The Abysmal","pinyin":"Kǎn","chinese":"坎","upper":"kan","lower":"kan","lines":[0,1,0,0,1,0],"judgment":"The doubled pit of danger: hold sincerity and let the heart stay true, so that whatever you do carries through with worth.","image":"Water flows on unceasing to its goal; the noble one holds fast to virtue and teaches the business of life without pause.","lineTexts":["Pit upon pit; falling into the very depth of the abyss — misfortune.","Danger all around within the pit; seek only small gains for now.","Pit met by pit at every turn, deep and sheer; do not act — you would only sink further.","A jug of wine, a bowl of rice, plain earthen vessels handed in through the window — in the end, no blame.","The pit is not yet full, only level to the brim — no blame.","Bound with cords and set among thorns, unable to break free for three years — misfortune."],"keywords":["danger","depth","water","perseverance","the abyss"]},
  {"num":30,"name":"The Clinging","pinyin":"Lí","chinese":"離","upper":"li","lower":"li","lines":[1,0,1,1,0,1],"judgment":"Clinging rewards constancy and brings success; caring for the cow brings good fortune.","image":"A double brightness clings on high; the great one carries his radiance into every quarter of the world.","lineTexts":["The footsteps come confused; keep your bearing steady, and there is no blame.","Clinging as the yellow light of noon — supreme good fortune.","Clinging in the light of the setting sun; drum on the pot and sing, or the old will wail in dread — misfortune.","Its coming is sudden — it flares up, dies out, and is cast aside.","Tears streaming, sighing and lamenting — yet from this sorrow comes good fortune.","The king goes forth to campaign; there is honor, he crushes the leaders and spares the rank and file — no blame."],"keywords":["clarity","attachment","radiance","fire","dependence"]},
  {"num":31,"name":"Influence","pinyin":"Xián","chinese":"咸","upper":"dui","lower":"gen","lines":[0,0,1,1,1,0],"judgment":"Influence brings success and rewards constancy; taking a wife brings good fortune.","image":"A lake on the mountain; the noble one keeps himself open and receives others with an empty, ready heart.","lineTexts":["The influence stirs in the big toe.","The influence stirs in the calves — misfortune to act; staying still brings good fortune.","The influence stirs in the thighs, clinging to whatever it follows; going on this way brings regret.","Steadfastness brings good fortune and regret vanishes; if your thoughts dart restlessly to and fro, only a few friends will follow.","The influence stirs in the back of the neck — no regret.","The influence stirs in the jaws, cheeks, and tongue — only talk."],"keywords":["attraction","influence","courtship","stimulus","responsiveness"]},
  {"num":32,"name":"Duration","pinyin":"Héng","chinese":"恆","upper":"zhen","lower":"xun","lines":[0,1,1,1,0,0],"judgment":"Duration brings success and no blame; constancy is rewarded, and it is well to have somewhere to go.","image":"Thunder and wind together, enduring; the noble one stands firm and does not change his course.","lineTexts":["Seeking depth of endurance too soon; steadfastness here brings misfortune, and nothing is gained.","Regret vanishes for one who can endure.","Not making one's virtue lasting invites disgrace; steadfastness brings humiliation.","No game in the hunting field — endurance in the wrong place finds nothing.","Making constancy one's virtue and holding firm; good fortune for the wife, misfortune for the husband.","Restless, agitated endurance — misfortune."],"keywords":["endurance","constancy","perseverance","steadiness","continuity"]},
  {"num":33,"name":"Retreat","pinyin":"Dùn","chinese":"遯","upper":"qian","lower":"gen","lines":[0,0,1,1,1,1],"judgment":"Retreat brings success. In withdrawing at the right moment there is progress; a small measure of persistence, in what is upright, is favorable. Yield ground to the encroaching dark, but do so with dignity, not defeat.","image":"Beneath heaven the mountain stands; heaven draws off and away. So the superior person keeps the inferior at a distance, not with anger but with a reserve that is measured and dignified.","lineTexts":["At the tail of the retreat there is danger; make no move, undertake nothing.","He binds himself fast with the hide of a yellow ox; none can loosen his resolve.","A retreat entangled by ties brings distress and sickness; yet keeping servants and maids is fortunate.","The noble person retreats willingly and prospers; the small person cannot.","An admirable retreat, correct and fortunate; his purpose stays firm.","A cheerful, unhampered retreat; everything furthers, nothing is amiss."],"keywords":["withdrawal","strategic distance","timing","dignity","yielding"]},
  {"num":34,"name":"The Power of the Great","pinyin":"Dà Zhuàng","chinese":"大壯","upper":"zhen","lower":"qian","lines":[1,1,1,1,0,0],"judgment":"The strength of the great. It is favorable to remain firm and upright. Great vigor is only truly great when it is bound to what is right; power without righteousness collapses into mere force.","image":"Thunder rolls high in the heavens: the image of great strength. The superior person does not tread any path that departs from what is proper.","lineTexts":["Strength shown in the toes; to advance now brings misfortune, and this is certain.","Persevering brings good fortune; the way ahead is open.","The small man uses his strength; the superior man does not. To push on is dangerous—like a ram butting a hedge and snaring its horns.","Perseverance brings fortune and regret fades; the hedge opens, the horns are freed. Strength like a great wagon's axle.","He loses the ram with ease, in the open field; no regret follows.","The ram butts the hedge and can neither retreat nor advance; nothing furthers—yet noting the difficulty brings good fortune."],"keywords":["great strength","vigor","righteous power","restraint","momentum"]},
  {"num":35,"name":"Progress","pinyin":"Jìn","chinese":"晉","upper":"li","lower":"kun","lines":[0,0,0,1,0,1],"judgment":"Progress. A powerful prince is honored with horses in abundance and granted audience three times in a single day. Steady advance into the light, rewarded and welcomed.","image":"The sun rises above the earth: the image of progress. The superior person of his own accord brightens his shining virtue.","lineTexts":["Advancing, yet turned back; be steadfast for fortune. Meeting no trust, stay calm and generous—no blame.","Advancing, yet sorrowful; persevere for good fortune. Great blessing comes from one's ancestress.","All are in accord; regret disappears.","Advancing like a hoarding rat—persisting in this brings danger.","Regret vanishes; take no account of loss or gain. To go forward is fortunate; all is favorable.","Advancing with the horns—used only to punish one's own city. Danger, yet good fortune and no blame; still, to persist is humbling."],"keywords":["advance","recognition","clarity rising","reward","ascent"]},
  {"num":36,"name":"Darkening of the Light","pinyin":"Míng Yí","chinese":"明夷","upper":"kun","lower":"li","lines":[1,0,1,0,0,0],"judgment":"The light is wounded and hidden. In hardship it is favorable to hold to what is right. When the brilliant is suppressed by the dark, veil your light and keep your inner resolve firm.","image":"The light has sunk into the earth: the image of the darkening of the light. The superior person, ruling the many, tempers his brilliance and yet stays luminous within.","lineTexts":["The light darkens in flight, drooping its wings. The noble one, traveling, eats nothing for three days; where he goes, his host has words against him.","The light darkens and wounds the left thigh; help comes with the strength of a horse—good fortune.","Darkening amid the southern hunt: the great chief is captured. One must not be too hasty to set things right.","He pierces to the left belly, reaching the very heart of the darkening, and departs through the gate.","Prince Ji's darkening of the light; steadfastness furthers.","No light, only darkness. First he mounted to heaven, then plunged into the earth."],"keywords":["hidden light","adversity","perseverance","concealment","inner integrity"]},
  {"num":37,"name":"The Family","pinyin":"Jiā Rén","chinese":"家人","upper":"xun","lower":"li","lines":[1,0,1,0,1,1],"judgment":"The family. The perseverance of the woman furthers. Order within the household—each member true to their place—is the seed of order in the wider world.","image":"Wind comes forth from fire: the image of the family. The superior person's words have substance, and his conduct has constancy.","lineTexts":["Firm seclusion within the family; regret disappears.","She need not follow her own whims; she tends the food within. Perseverance brings good fortune.","When tempers in the family flare too hot, remorse and danger follow—yet fortune remains. If wife and child only trifle and laugh, humiliation comes at last.","She is the treasure of the house; great good fortune.","As a king he draws near to his family; fear not—good fortune.","His work commands sincerity and reverence; in the end, good fortune."],"keywords":["family order","roles","constancy","household","influence"]},
  {"num":38,"name":"Opposition","pinyin":"Kuí","chinese":"睽","upper":"li","lower":"dui","lines":[1,1,0,1,0,1],"judgment":"Opposition. In small matters, good fortune. When wills diverge and estrangement rules, greatness cannot be forced; attend to the small, and unity slowly returns.","image":"Above, fire; below, the lake—moving apart: the image of opposition. The superior person, amid all fellowship, keeps his own distinctness.","lineTexts":["Regret vanishes. If you lose your horse, do not chase it—it returns of itself. When you meet evil people, guard against mistakes.","One meets his lord in a narrow lane; no blame.","One sees the wagon dragged back, the oxen halted, its driver's hair and nose cut off. No good beginning, but a good end.","Isolated by opposition, he meets a like-minded friend; they join in trust. Danger, yet no blame.","Regret disappears. The companion bites through the wrappings. To go forward—what blame could there be?","Isolated by opposition, he sees a pig covered in filth, a wagon full of demons. First he draws the bow, then lays it aside—no robber, but a suitor. Going on, meeting rain, brings good fortune."],"keywords":["estrangement","divergence","small steps","reconciliation","distinctness"]},
  {"num":39,"name":"Obstruction","pinyin":"Jiǎn","chinese":"蹇","upper":"kan","lower":"gen","lines":[0,0,1,0,1,0],"judgment":"Obstruction. The southwest is favorable, the northeast is not. It furthers one to see the great person. Perseverance in what is right brings good fortune. When the way is blocked, seek allies and steady counsel rather than forcing ahead.","image":"Water upon the mountain: the image of obstruction. The superior person turns his attention inward and refines his own character.","lineTexts":["Going leads into obstruction; coming brings praise.","The king's servant meets obstruction upon obstruction—yet it is not for his own sake.","Going leads into obstruction; so he comes back and turns within.","Going leads into obstruction; coming brings union.","In the midst of the greatest obstruction, friends come.","Going leads into obstruction; coming brings greatness and good fortune. It furthers one to see the great person."],"keywords":["obstacle","difficulty","allies","inward turning","perseverance"]},
  {"num":40,"name":"Deliverance","pinyin":"Xiè","chinese":"解","upper":"zhen","lower":"kan","lines":[0,1,0,1,0,0],"judgment":"Deliverance. The southwest is favorable. If there is nowhere still to go, return brings good fortune. If there is somewhere to go, then early action is fortunate. As tension breaks, resolve what remains promptly and let the rest rest.","image":"Thunder and rain arise: the image of deliverance. The superior person pardons faults and is lenient toward transgressions.","lineTexts":["Without blame.","One catches three foxes in the field and receives a yellow arrow; persevering brings good fortune.","A porter riding in a carriage tempts robbers to approach; to persist thus brings humiliation.","Free yourself from the great toe; then the true companion comes, and in him is trust.","Only the superior person can deliver himself; good fortune. This proves his sincerity to the small people.","The prince shoots a hawk on a high wall; he takes it. Nothing that does not further."],"keywords":["release","resolution","liberation","promptness","forgiveness"]},
  {"num":41,"name":"Decrease","pinyin":"Sǔn","chinese":"損","upper":"gen","lower":"dui","lines":[1,1,0,0,0,1],"judgment":"Decrease with sincerity brings supreme good fortune, without blame. One may persevere; it furthers to undertake something. And how? Two small bowls may suffice for the offering. Loss below adds strength above when the heart is true.","image":"At the foot of the mountain lies the lake: the image of decrease. The superior person curbs his anger and restrains his desires.","lineTexts":["When your own affairs are done, go quickly to help—no blame. But weigh well how much you may decrease another.","Perseverance furthers; to set forth brings misfortune. Give without diminishing yourself.","When three travel together, they lose one; one who travels alone finds a companion.","If a man lessens his failings, letting the other hasten to rejoice, there is no blame.","Someone increases him—ten pairs of tortoises cannot oppose it. Supreme good fortune.","If one is increased without decreasing others, there is no blame. Perseverance brings good fortune; it furthers to undertake something. He gains servants but no longer a separate home."],"keywords":["reduction","sacrifice","sincerity","simplicity","restraint"]},
  {"num":42,"name":"Increase","pinyin":"Yì","chinese":"益","upper":"xun","lower":"zhen","lines":[1,0,0,0,1,1],"judgment":"Increase. It furthers one to undertake something; it furthers one to cross the great water. Now is the moment when those above give to those below, and the movement brings joy and progress.","image":"Wind and thunder: the image of increase. When the superior person sees good, he imitates it; when he sees a fault, he corrects it in himself.","lineTexts":["It furthers to accomplish great deeds; supreme good fortune, no blame.","Someone increases him—ten pairs of tortoises cannot oppose it. Lasting perseverance brings good fortune. The king presents his offering to God; good fortune.","One is enriched through unfortunate events. No blame, if you are sincere and walk in the middle, reporting to the prince with a seal.","If you walk in the middle and report to the prince, he follows. It furthers to be relied upon in moving the capital.","If in truth you have a kind heart, ask not—supreme good fortune. Truly, kindness will be recognized as your virtue.","He brings increase to no one; indeed, someone strikes him. He does not keep his heart steady. Misfortune."],"keywords":["gain","generosity","growth","reform","benefit below"]},
  {"num":43,"name":"Breakthrough","pinyin":"Guài","chinese":"夬","upper":"dui","lower":"qian","lines":[1,1,1,1,1,0],"judgment":"Breakthrough. The matter must be openly declared at the royal court. Proclaim it truthfully—danger remains. Warn your own city; do not resort to arms. It furthers one to have somewhere to go. Resolve the wrong by frank exposure, not by force.","image":"The lake has risen up to heaven: the image of breakthrough. The superior person dispenses riches downward and shuns resting on his virtue.","lineTexts":["Mighty in the forward toes; going without being equal to it turns into a fault.","A cry of alarm—arms at evening and night. Fear nothing.","To be firm-jawed brings misfortune. The superior person walks on alone and meets the rain; he is soiled and grumbled at, but in the end no blame.","There is no skin on his thighs, and walking comes hard. Led like a sheep, regret would vanish—but the words are not believed.","On dealing with weeds, resolute action is needed. To walk the middle brings freedom from blame.","No cry. In the end, misfortune comes."],"keywords":["resolution","decisive action","exposure","openness","determination"]},
  {"num":44,"name":"Coming to Meet","pinyin":"Gòu","chinese":"姤","upper":"qian","lower":"xun","lines":[0,1,1,1,1,1],"judgment":"Coming to meet. The maiden is powerful; one should not marry such a maiden. A single dark force returns and offers itself; welcome it in small things, but do not let it bind you or gain the upper hand.","image":"Under heaven, wind: the image of coming to meet. The prince acts by spreading his commands and making them known throughout the land.","lineTexts":["Check it with a brake of bronze; perseverance brings good fortune. If you let it run, misfortune follows—like a lean pig sure to bolt.","There is a fish in the tank; no blame. But it does not further guests.","There is no skin on his thighs, and walking comes hard. If mindful of danger, no great fault.","No fish in the tank; this gives rise to misfortune.","A melon covered with willow leaves—hidden lines, veiled beauty. Then it drops from heaven of itself.","He comes to meet with his horns; humiliation, but no blame."],"keywords":["encounter","temptation","the returning dark","caution","containment"]},
  {"num":45,"name":"Gathering Together","pinyin":"Cuì","chinese":"萃","upper":"dui","lower":"kun","lines":[0,0,0,1,1,0],"judgment":"Gathering together brings success. The king approaches his temple. It furthers to see the great person; there is progress through perseverance. A great offering brings good fortune; it furthers to undertake something. When people assemble, unity needs a center and a sincere leader.","image":"The lake rests over the earth: the image of gathering together. The superior person keeps his weapons in repair to meet the unforeseen.","lineTexts":["If you are sincere but not to the end, then there is confusion, then gathering. If you call out, one grasp of the hand can turn lament to laughter. Fear nothing; go forward without blame.","Letting oneself be drawn brings good fortune and freedom from blame. If sincere, even a small offering suffices.","Gathering together amid sighs; nothing furthers. Go forward without blame, though slightly humbling.","Great good fortune—and only so, no blame.","If in gathering one holds a high place with no sincere response, then persevere—regret disappears.","Sighing, lamenting, floods of tears. No blame."],"keywords":["assembly","unity","leadership","sincerity","congregation"]},
  {"num":46,"name":"Pushing Upward","pinyin":"Shēng","chinese":"升","upper":"kun","lower":"xun","lines":[0,1,1,0,0,0],"judgment":"Pushing upward has supreme success. One must see the great person; fear not. Departure toward the south brings good fortune. Effortless, gradual ascent—like a plant growing from the earth—rewards steady, patient advance.","image":"Within the earth, wood grows: the image of pushing upward. The superior person, with devoted character, heaps up small things to achieve the high and great.","lineTexts":["Pushing upward that meets with confidence brings great good fortune.","If one is sincere, even a small offering suffices; no blame.","One pushes upward into an empty city.","The king offers him Mount Qi; good fortune, no blame.","Perseverance brings good fortune; one pushes upward by steps, like a stair.","Pushing upward in the dark. It furthers only unremitting perseverance."],"keywords":["ascent","gradual growth","effort","patience","advancement"]},
  {"num":47,"name":"Oppression","pinyin":"Kùn","chinese":"困","upper":"dui","lower":"kan","lines":[0,1,0,1,1,0],"judgment":"Oppression, yet success. Perseverance—for the great person good fortune, and no blame. But words now find no belief. When exhausted and confined, hold your inner cheer and speak little, letting deeds prove your worth.","image":"There is no water in the lake: the image of exhaustion. The superior person stakes his life on following his will.","lineTexts":["He sits oppressed under a bare tree, sunk into a gloomy valley; for three years he sees nothing.","Oppressed while at meat and drink; then the scarlet sashes come. It furthers to bring an offering. To set forth brings misfortune, but there is no blame.","Oppressed by stone, resting on thorns; he enters his house and does not see his wife. Misfortune.","He comes very quietly, oppressed in a golden carriage. Humiliation, but the end is reached.","His nose and feet are cut off; oppressed by the man in scarlet. Joy comes gently; it furthers to make offerings.","Oppressed by creeping vines, on shaky ground; to move is to regret. If, feeling regret, one sets forth, good fortune."],"keywords":["exhaustion","adversity","confinement","endurance","inner strength"]},
  {"num":48,"name":"The Well","pinyin":"Jǐng","chinese":"井","upper":"kan","lower":"xun","lines":[0,1,1,0,1,0],"judgment":"The well. Towns may change, but the well does not change; it neither empties nor overflows. People come and go and draw from it. But if the rope does not reach the water, or the jug breaks—misfortune. The source of nourishment is constant; failing to reach it is the danger.","image":"Water over wood: the image of the well. The superior person encourages the people at their work and urges them to help one another.","lineTexts":["The well is muddy; none drink of it. No animals come to an old well.","At the wellhole one shoots fish; the jug is cracked and leaks.","The well is cleansed, yet none drink from it. This is the sorrow of my heart, for the water might be drawn. If the king were clear-sighted, all would share the blessing.","The well is being lined with stone; no blame.","The well has a cool, clear spring from which one may drink.","One draws from the well without hindrance; it is dependable. Supreme good fortune."],"keywords":["source","nourishment","constancy","community","depth"]},
  {"num":49,"name":"Revolution","pinyin":"Gé","chinese":"革","upper":"dui","lower":"li","lines":[1,0,1,1,1,0],"judgment":"Revolution. On your own day you are believed. Supreme success through perseverance; regret disappears. Change is trusted only when its time is ripe and its cause is just; then remorse falls away.","image":"Fire within the lake: the image of revolution. The superior person orders the calendar and makes the seasons clear.","lineTexts":["Wrapped in the hide of a yellow ox; hold firm and do not yet act.","When your own day has come, then you may bring about revolution. To set forth brings good fortune, without blame.","To set forth brings misfortune; persevere, for danger is near. When talk of revolution has come round three times, then one may commit oneself, and confidence follows.","Regret disappears; if men trust you, then to change the mandate brings good fortune.","The great man changes like a tiger; even before he consults the oracle, he is believed.","The superior person changes like a leopard; the inferior molt only in the face. To set forth now brings misfortune; to remain firm brings good fortune."],"keywords":["change","transformation","timing","renewal","legitimacy"]},
  {"num":50,"name":"The Cauldron","pinyin":"Dǐng","chinese":"鼎","upper":"li","lower":"xun","lines":[0,1,1,1,0,1],"judgment":"The cauldron. Supreme good fortune and success. The sacred vessel that cooks nourishment for the gods and the worthy—symbol of culture refined, of the raw transformed into the noble.","image":"Fire over wood: the image of the cauldron. The superior person, by making his position correct, consolidates his destiny.","lineTexts":["The cauldron is overturned to empty out its stagnant refuse. One takes a concubine for her son; no blame.","There is food in the cauldron; my comrades are envious, but they cannot harm me. Good fortune.","The cauldron's handle is altered; one's course is blocked, the fat pheasant goes uneaten. When the rain comes, regret is spent—good fortune in the end.","The cauldron's legs break; the prince's meal is spilled, and his person is soiled. Misfortune.","The cauldron has yellow handles and rings of gold. Perseverance furthers.","The cauldron has rings of jade. Great good fortune; nothing that does not further."],"keywords":["nourishment","transformation","culture","refinement","the sacred vessel"]},
  {"num":51,"name":"The Arousing","pinyin":"Zhèn","chinese":"震","upper":"zhen","lower":"zhen","lines":[1,0,0,1,0,0],"judgment":"Shock brings success. When the shock comes—terror and dread—yet afterward laughter and words. The thunder alarms for a hundred miles, but he does not let fall the sacrificial spoon and chalice. Sudden fear that is met with composure ripens into reverence.","image":"Thunder repeated: the image of shock. In fear and trembling the superior person examines himself and sets his life in order.","lineTexts":["The shock comes—terror and dread; then laughter and words follow. Good fortune.","The shock comes with danger. A hundred thousand times you lose your treasures and must climb the nine hills. Do not chase them; after seven days you regain them.","Shock brings distress and unrest. If action is spurred by shock, one stays free of misfortune.","The shock is mired in the mud.","Shock comes and goes—danger. Yet nothing at all is lost; there are still things to be done.","The shock brings ruin and terrified looks around. To go on brings misfortune. If it strikes the neighbor before oneself, there is no blame; only one's kin will murmur."],"keywords":["shock","awakening","reverence","composure","sudden movement"]},
  {"num":52,"name":"Keeping Still","pinyin":"Gèn","chinese":"艮","upper":"gen","lower":"gen","lines":[0,0,1,0,0,1],"judgment":"Keeping still, the mountain. When one keeps his back still so that he no longer feels his body, and walks in his courtyard without seeing his people, there is no blame. Stillness at the right moment, movement at the right moment—herein lies clarity.","image":"Mountains standing joined: the image of keeping still. The superior person does not let his thoughts stray beyond his situation.","lineTexts":["Keeping his toes still; no blame. Continued perseverance furthers.","Keeping his calves still; he cannot rescue the one he follows, and his heart is heavy.","Keeping his hips still, stiffening the small of his back—dangerous, and the heart suffocates.","Keeping his trunk still; no blame.","Keeping his jaws still; his words are orderly, and regret disappears.","Noble-hearted keeping still; good fortune."],"keywords":["stillness","meditation","boundaries","composure","the mountain"]},
  {"num":53,"name":"Development","pinyin":"Jiàn","chinese":"漸","upper":"xun","lower":"gen","lines":[0,0,1,0,1,1],"judgment":"Development. The maiden is given in marriage; good fortune. Perseverance furthers. Growth unfolds by gradual, ordered stages—like a tree upon the mountain—and only what ripens slowly endures.","image":"On the mountain, a tree: the image of gradual development. The superior person abides in dignity and virtue, and so improves the customs of the people.","lineTexts":["The wild goose draws near the shore. The young son is in danger; there is talk, but no blame.","The wild goose draws near the cliff; it eats and drinks in peace and joy. Good fortune.","The wild goose draws near the plateau. The man goes forth and does not return; the woman conceives but does not bring forth. Misfortune. It furthers to fight off robbers.","The wild goose draws near the tree; perhaps it finds a flat branch to rest on. No blame.","The wild goose draws near the summit. For three years the woman has no child; yet in the end nothing can hinder her. Good fortune.","The wild goose draws near the cloud-heights. Its feathers can be used in the sacred dance. Good fortune."],"keywords":["gradual progress","patience","stages","marriage","steady growth"]},
  {"num":54,"name":"The Marrying Maiden","pinyin":"Guī Mèi","chinese":"歸妹","upper":"zhen","lower":"dui","lines":[1,1,0,1,0,0],"judgment":"The marrying maiden. To set forth brings misfortune; nothing that would further. When one enters a bond in a subordinate, irregular place, undertakings go awry; know the limits of the position you take.","image":"Thunder over the lake: the image of the marrying maiden. The superior person understands the transitory in light of the eternity of the end.","lineTexts":["The maiden marries as a secondary wife. A lame man who can still tread; to go forward brings good fortune.","A one-eyed man who can still see. The perseverance of a solitary person furthers.","The maiden waits to marry, and marries at last as a secondary wife.","The maiden delays; a late marriage comes in due time.","The Emperor Yi gave his daughter in marriage; her embroidered robes were less fine than the handmaid's. The moon nearly full—good fortune.","The woman holds a basket, but there are no fruits in it. The man stabs the sheep, but no blood flows. Nothing that furthers."],"keywords":["subordinate union","impropriety","limits","transience","tact"]},
  {"num":55,"name":"Abundance","pinyin":"Fēng","chinese":"豐","upper":"zhen","lower":"li","lines":[1,0,1,1,0,0],"judgment":"Abundance has success. The king attains it; be not sad—be like the sun at midday. Fullness is fleeting; enjoy it without anxiety while it lasts, knowing that noon must decline toward evening.","image":"Both thunder and lightning come: the image of abundance. The superior person decides lawsuits and carries out punishments.","lineTexts":["He meets the lord who is his match; ten days without blame. To go forward wins recognition.","So great the abundance that at noon the polestars are seen. To go forth brings mistrust and hate; but if sincere and open, good fortune.","Such abundance of screening growth that the small stars are seen at noon. He breaks his right arm; no blame.","Such abundance of screening that at noon the polestars are seen. He meets his equal lord; good fortune.","Lines are coming; blessing and fame draw near. Good fortune.","His house is in abundance, yet he screens off his family. He peers through the gate—no one there, solitary for three years. Misfortune."],"keywords":["fullness","zenith","abundance","transience","clarity"]},
  {"num":56,"name":"The Wanderer","pinyin":"Lǚ","chinese":"旅","upper":"li","lower":"gen","lines":[0,0,1,1,0,1],"judgment":"The wanderer. Success through smallness. Perseverance brings good fortune to the wanderer. A stranger far from home should keep to modesty and caution; only small matters go well.","image":"Fire upon the mountain: the image of the wanderer. The superior person applies penalties with clarity and caution, and does not drag out lawsuits.","lineTexts":["If the wanderer busies himself with trifles, he draws down misfortune on himself.","The wanderer comes to an inn; he carries his possessions and wins a young servant's loyalty.","The wanderer's inn burns down; he loses his young servant. Persevering, he faces danger.","The wanderer rests in a shelter and has his goods and an axe; yet his heart is not glad.","He shoots a pheasant; it drops with the first arrow. In the end this brings praise and high office.","The bird's nest burns; the wanderer first laughs, then must weep and lament. Through carelessness he loses his cow. Misfortune."],"keywords":["stranger","travel","impermanence","modesty","caution"]},
  {"num":57,"name":"The Gentle","pinyin":"Xùn","chinese":"巽","upper":"xun","lower":"xun","lines":[0,1,1,0,1,1],"judgment":"The gentle, penetrating wind. Success through what is small. It furthers to have somewhere to go; it furthers to see the great person. Persistent, mild influence, like wind that reaches everywhere, works its effect where force cannot.","image":"Winds following upon one another: the image of the gently penetrating. The superior person spreads his commands abroad and carries out his undertakings.","lineTexts":["Advancing and retreating in turn. The perseverance of a warrior furthers.","Penetration under the bed. Priests and magi are employed in great number; good fortune, no blame.","Repeated, forced penetration; humiliation.","Regret vanishes. In the hunt three kinds of game are taken.","Perseverance brings good fortune; regret disappears; nothing that does not further. No beginning, but an end. Three days before the change, three days after—good fortune.","Penetration under the bed; he loses his goods and his axe. Perseverance brings misfortune."],"keywords":["penetration","gentleness","influence","adaptability","persistence"]},
  {"num":58,"name":"The Joyous","pinyin":"Duì","chinese":"兌","upper":"dui","lower":"dui","lines":[1,1,0,1,1,0],"judgment":"The joyous, the lake. Success. Perseverance furthers. True gladness, shared and heartfelt, encourages people to endure hardship and even to forget death—but its foundation must be inner steadfastness.","image":"Lakes resting one on the other: the image of the joyous. The superior person joins with friends for discussion and practice.","lineTexts":["Contented joyousness; good fortune.","Sincere joyousness; good fortune, and regret disappears.","Joyousness that comes courting from without; misfortune.","Joyousness weighed and deliberated is not yet at peace. After ridding oneself of faults, there is gladness.","Sincerity toward disintegrating forces is dangerous.","Seductive, luring joyousness."],"keywords":["joy","openness","encouragement","sincerity","fellowship"]},
  {"num":59,"name":"Dispersion","pinyin":"Huàn","chinese":"渙","upper":"xun","lower":"kan","lines":[0,1,0,0,1,1],"judgment":"Dispersion. Success. The king approaches his temple. It furthers to cross the great water; perseverance furthers. What is rigid and divided must be dissolved—hardness of heart melted, egotism scattered—so that a greater unity can form.","image":"Wind moves over the water: the image of dispersion. The kings of old sacrificed to God and built temples.","lineTexts":["He brings aid with the strength of a horse; good fortune.","Amid dispersion, he hurries to that which supports him; regret disappears.","He dissolves his own self; no regret.","He disperses his group; supreme good fortune. Dispersion leads in turn to accumulation—something ordinary minds do not foresee.","He scatters his sweat with loud cries. Dispersion—a king abides without blame.","He disperses his blood; departing, keeping at a distance, going out—no blame."],"keywords":["dissolution","scattering","reunion","letting go","fluidity"]},
  {"num":60,"name":"Limitation","pinyin":"Jié","chinese":"節","upper":"kan","lower":"dui","lines":[1,1,0,0,1,0],"judgment":"Limitation. Success. But galling limitation must not be persevered in. Boundaries bring order and success, yet limits pressed too hard turn bitter; even restraint must be practiced in measure.","image":"Water over the lake: the image of limitation. The superior person creates number and measure, and examines the nature of virtue and right conduct.","lineTexts":["One does not go out of the door and the courtyard; no blame.","One does not go out of the gate and the courtyard; misfortune.","One who knows no limitation will have cause to lament. No blame.","Contented limitation; success.","Sweet limitation brings good fortune. Going forward wins esteem.","Galling limitation; to persevere brings misfortune, but regret disappears."],"keywords":["boundaries","moderation","measure","discipline","restraint"]},
  {"num":61,"name":"Inner Truth","pinyin":"Zhōng Fú","chinese":"中孚","upper":"xun","lower":"dui","lines":[1,1,0,0,1,1],"judgment":"Inner truth. Even pigs and fishes are moved—good fortune. It furthers to cross the great water; perseverance furthers. Sincerity so deep that it reaches even the most unresponsive creatures is the ground of all influence.","image":"Wind over the lake: the image of inner truth. The superior person deliberates over criminal cases and delays executions.","lineTexts":["Being prepared brings good fortune. If there are secret designs, it is disquieting.","A crane calls in the shade; its young answers. I have a good goblet; I will share it with you.","He finds a comrade. Now he beats the drum, now he stops; now he sobs, now he sings.","The moon nearly full; the team-horse goes astray. No blame.","He possesses truth that binds together like a knot; no blame.","The crowing cock tries to rise to heaven. Perseverance brings misfortune."],"keywords":["sincerity","trust","inner conviction","influence","truthfulness"]},
  {"num":62,"name":"Preponderance of the Small","pinyin":"Xiǎo Guò","chinese":"小過","upper":"zhen","lower":"gen","lines":[0,0,1,1,0,0],"judgment":"Preponderance of the small. Success through perseverance. Small things may be done, great things should not. The flying bird brings the message: it should not strive upward, but come down—there below is great good fortune.","image":"Thunder on the mountain: the image of preponderance of the small. In conduct the superior person gives preponderance to reverence; in mourning, to grief; in spending, to thrift.","lineTexts":["The bird meets misfortune through flying too high.","She passes by her ancestor and meets her ancestress; he does not reach his prince, but meets the official. No blame.","If one is not extremely careful, someone may come up from behind and strike. Misfortune.","No blame. He meets the other without passing by. Going ahead is dangerous; one must be on guard. Do not act; be constant and enduring.","Dense clouds, no rain, from our western region. The prince shoots and takes the one in the cave.","He passes by, not meeting; the flying bird leaves him. Misfortune—this means calamity and injury."],"keywords":["small excess","modesty","attention to detail","caution","humility"]},
  {"num":63,"name":"After Completion","pinyin":"Jì Jì","chinese":"既濟","upper":"kan","lower":"li","lines":[1,0,1,0,1,0],"judgment":"After completion. Success in small matters. Perseverance furthers. At the outset good fortune, at the end disorder. When all is at last in order, the peak is passed; vigilance alone guards against the slide into decay.","image":"Water over fire: the image of the condition after completion. The superior person takes thought of misfortune and arms himself against it in advance.","lineTexts":["He brakes his wheels; the fox gets its tail wet. No blame.","The woman loses the curtain of her carriage. Do not chase it; on the seventh day you will get it back.","The Illustrious Ancestor disciplines the Devil's Country; in three years he conquers it. Small people should not be employed.","The finest clothes turn to rags; be cautious all day long.","The neighbor in the east who slays an ox does not attain the real blessing that the neighbor in the west attains with his small offering.","He gets his head in the water. Danger."],"keywords":["completion","order","vigilance","climax","decline"]},
  {"num":64,"name":"Before Completion","pinyin":"Wèi Jì","chinese":"未濟","upper":"li","lower":"kan","lines":[0,1,0,1,0,1],"judgment":"Before completion. Success. But if the little fox, nearly across the stream, gets its tail wet, then nothing furthers. Transition nears its end; only careful, well-judged effort to the very last carries it through.","image":"Fire over water: the image of the condition before completion. The superior person is careful in the discrimination of things, so that each finds its place.","lineTexts":["He gets his tail wet; humiliating.","He brakes his wheels; perseverance brings good fortune.","Before completion, to set forth brings misfortune. Yet it furthers to cross the great water.","Perseverance brings good fortune; regret vanishes. With shaking and vigor one disciplines the Devil's Country. For three years, great rewards from the great kingdom.","Perseverance brings good fortune, with no regret. The light of the superior person is true; good fortune.","With genuine confidence one drinks wine; no blame. But if one wets his head, then even in sincerity one loses what is right."],"keywords":["transition","not yet across","caution","potential","threshold"]},
];

const HEX_BY_BITS = new Map(HEXAGRAMS.map(h => [h.lines.join(''), h]));
const HEX_BY_NUM = new Map(HEXAGRAMS.map(h => [h.num, h]));
const TRIG_BY_BITS = new Map(TRIGRAMS.map(t => [t.lines.join(''), t]));
const TRIG_BY_KEY = new Map(TRIGRAMS.map(t => [t.key, t]));
export function hexagramByLines(lines) { return HEX_BY_BITS.get(lines.join('')) || null; }
export function hexagramByNum(n) { return HEX_BY_NUM.get(n) || null; }
export function trigramByLines(lines) { return TRIG_BY_BITS.get(lines.join('')) || null; }
export function trigramByKey(k) { return TRIG_BY_KEY.get(k) || null; }
